local StartCtrlBase = LXImport(".StartCtrlBase")
---guideType 1
---@class StartCtrlNewOne
local StartCtrlNewOne = LxClass("StartCtrlNewOne", StartCtrlBase)

function StartCtrlNewOne:StartCtrlNewOne()

end

function StartCtrlNewOne:OnSceneLoaded()
    self._doAfter = false

    local bPlot = not gModelPlot:IsStartPlayed() or not gModelPlot:IsStartPlayEnded()
    if PRODUCT_G_VER ~= 0 then
        bPlot = false
    end
    
    local blockMiniGameFlag = gModelBlockMiniGame:GetWXBSFlag()
    if(blockMiniGameFlag)then
        return "LCityMap"
    end
    
    if bPlot then
        GF.OpenWnd('UIMCity')
        GF.OpenWndTop("UISayFlow")
        self._doAfter = true
        return "LNewbieMap"
    else
        GF.OpenWnd('UIMCity')
        GF.OpenWndTop("UISayFlow")
        local battleNode = tonumber(gModelPlot:GetPara("storynovicecombat"))
        if battleNode and battleNode > 0 then
            if not gModelInstance:IsBattleNodePass(battleNode) then
                self._doAfter = true
            end
        end
    end

    if not gModelFunctionOpen:CheckIsOpened(10000000, false) then
        FireEvent(EventNames.ONLY_CHANGE_MAIN_BTN_ON, {index=LMainBtnIndexConst.ADVENTURE})
        return "LFightIdleMap"
    else
        return "LCityMap"
    end
end

function StartCtrlNewOne:OnSceneEnterFinished(toBattle)
    if not self._doAfter then
        return
    end

    local bPlot = not gModelPlot:IsStartPlayEnded()
    if PRODUCT_G_VER ~= 0 then
        bPlot = false
    end
    if bPlot then
        local has,refId,type = gModelPlot:CheckRestartStory() --剧情重登
        if has then
            gModelPlot:TryRestartStory(type,refId)
        else
            gModelPlot:PlayStartStory()
        end
        return
    end

    local battleNode = tonumber(gModelPlot:GetPara("storynovicecombat"))
    if battleNode and battleNode > 0 then
        if not gModelInstance:IsBattleNodePass(battleNode) then
            FireEvent(EventNames.ONLY_CHANGE_MAIN_BTN_ON, {index=LMainBtnIndexConst.ADVENTURE})
            --gModelInstance:GotoChallenge()
            gModelBattle:FirstGotoMainBattle()
            return
        end
    end
end



return  StartCtrlNewOne